// === 言語コードを国旗に変換 ===
function flagFor(lang) {
  if (lang === 'ja') return '🇯🇵';
  if (lang === 'en') return '🇺🇸';
  return '🌐';
}

// Detect Language ノードから言語を取得
const sourceLang = $node["Detect Language"].json.source_lang || 'en';
const targetLang = $node["Detect Language"].json.target_lang || 'en';

const src = flagFor(sourceLang);
const dst = flagFor(targetLang);

// Telegram ユーザー名
const username = $node["Get File ID"].json.from_username || 'unknown';

// Whisper or Detect Language の原文テキスト
const original =
  $node["Extract Transcript"].json.text ||
  $node["Detect Language"].json.original_text ||
  '(no transcript)';

// 翻訳結果
const translated =
  $node["Translate (OpenAI)"].json.choices[0].message.content ||
  '(no translation)';

// Slackに投稿する本文
const text = `*${src} → ${dst}* (@${username})
> ${original}

${translated}
`;

return [{ json: { slack_text: text } }];

